# verify.jl -- triangulate three sources for Phase 4 StepControl oracle,
# then emit test/_oracle_stepcontrol.jl.
#
# Sources:
#   oracles_julia.txt   <- TaylorIntegration.stepsize (canonical Julia)
#   oracles_python.txt  <- mpmath at 50 dps + sympy.solve
#   oracles_wolfram.txt <- Mathematica N[..., 50] + NSolve
#
# Asserts all three agree on h_4_1_1_min to Float64 precision, and on
# the step values for 4.1.3 / 4.1.4 (which are exact: 2.0 and 3.0).

using Printf

const HERE = @__DIR__
const PROJECT_ROOT = abspath(joinpath(HERE, "..", "..", ".."))
const O_JL = joinpath(HERE, "oracles_julia.txt")
const O_WL = joinpath(HERE, "oracles_wolfram.txt")
const PINNED = joinpath(PROJECT_ROOT, "test", "_oracle_stepcontrol.jl")

# Parse a Python repr-format complex tuple like "(3-1j)" into ComplexF64,
# or pass-through Float64.  We don't try to load oracles_python.txt as
# Julia source since Python uses (3-1j) for complex literals; instead we
# just regex-extract the scalar h value below.

module _OJL end
module _OWL end

Base.include_string(_OJL, read(O_JL, String), O_JL)
Base.include_string(_OWL, read(O_WL, String), O_WL)

# Pull Python's h_4_1_1_min from oracles_python.txt by regex.
const py_text = read(joinpath(HERE, "oracles_python.txt"), String)
m = match(r"h_4_1_1_min\s*=\s*([0-9eE+\-.]+)", py_text)
m === nothing && error("Could not parse h_4_1_1_min from oracles_python.txt")
const h_py = parse(Float64, m.captures[1])

# 50-dps strings (the load-bearing high-precision pin).
m = match(r"h_4_1_1_min_50dps\s*=\s*\"([0-9eE+\-.]+)\"", py_text)
m === nothing && error("Could not parse h_4_1_1_min_50dps from oracles_python.txt")
const h_py_50dps = m.captures[1]

# ─── Cross-check ──────────────────────────────────────────────────────

# Float64-level agreement.
let
    h_jl = _OJL.h_4_1_1_TI
    h_wl = _OWL.h_4_1_1_min_wl
    @assert isapprox(h_jl, h_py;     rtol = 1e-15) "h_TI=$h_jl  h_py=$h_py"
    @assert isapprox(h_jl, h_wl;     rtol = 1e-15) "h_TI=$h_jl  h_wl=$h_wl"
    @printf("4.1.1 step_jorba_zou: TI.jl ≡ mpmath ≡ wolframscript = %.16f\n", h_jl)
end

# 50-dps string agreement (mpmath ≡ wolframscript).
let
    h_wl_50dps = _OWL.h_4_1_1_min_wl_50dps
    @assert h_py_50dps == h_wl_50dps "50-dps disagreement:\n  py: $h_py_50dps\n  wl: $h_wl_50dps"
    println("4.1.1 50-dps string match (mpmath ≡ wolframscript): $h_wl_50dps")
end

# Step values for 4.1.3 / 4.1.4 — exact integer-valued.
let
    @assert _OJL.step_4_1_3_expected == 2.0
    @assert _OWL.step_4_1_3_expected_wl == 2.0
    @assert _OJL.step_4_1_4_expected == 3.0
    @assert _OWL.step_4_1_4_expected_wl == 3.0
    println("4.1.3 step = 2.0 (TI.jl ≡ wolframscript ≡ sympy)")
    println("4.1.4 step = 3.0 (TI.jl ≡ wolframscript ≡ sympy)")
end

# ─── Emit canonical test/_oracle_stepcontrol.jl ──────────────────────
open(PINNED, "w") do io
    print(io, """
# test/_oracle_stepcontrol.jl -- Phase 4 oracle, pinned values.
#
# This file is auto-generated by:
#   external/probes/stepcontrol-oracle/verify.jl
# from three independent sources cross-checked to agree at Float64
# precision (and to 47 decimal digits for the high-precision pin):
#
#   oracles_julia.txt   <- TaylorIntegration.stepsize (canonical Julia)
#   oracles_python.txt  <- mpmath/sympy
#   oracles_wolfram.txt <- Mathematica
#
# Do NOT hand-edit.  Re-run capture.{jl,py,wl} + verify.jl to update;
# verify.jl asserts three-way agreement before writing.

""")
    print(io, read(O_JL, String))
end

println("Wrote ", PINNED)
